<template>
  <div class="box">
    <div class="loginwindow">
      <div style="padding-top:30px"><h1 style="font-size: 45px">图书管理系统</h1></div><br/><br/><br/>
  <Form ref="formInline" :model="formInline" :rules="ruleInline" inline>
    <FormItem prop="user">
      <Input type="text" v-model="formInline.account" placeholder="请输入用户名"  >
        <Icon type="ios-person-outline" slot="prepend"></Icon>
      </Input>
    </FormItem><br/><br/><br/>
    <FormItem prop="password">
      <Input type="password" v-model="formInline.password" placeholder="请输入密码">
        <Icon type="ios-lock-outline" slot="prepend"></Icon>
      </Input>
    </FormItem><br/><br/><br/>
    <FormItem>
      <Button type="primary" @click="handleSubmit()">登录</Button>
      <Button type="primary" @click="insertWindowopen">注册</Button>
    </FormItem>
  </Form>
    </div>
    <!--添加用户弹窗-->
    <el-dialog title="添加用户" :visible.sync="insertVisible" width="500px">
      <el-form :model="insertform" >
        <!--<el-form-item label="用户名称" :label-width="formLabelWidth" >-->
        <!--<el-input v-model="insertform.user_name"  autocomplete="off"></el-input>-->
        <!--</el-form-item>-->
        <el-form-item label="用户账号" :label-width="formLabelWidth" style="text-align: center">
          <el-input v-model="insertform.account" autocomplete="off" style="width: 300px ; text-align: center"></el-input>
        </el-form-item>
        <el-form-item label="密码" :label-width="formLabelWidth" style="text-align: center">
          <el-input v-model="insertform.password" autocomplete="off" style="width: 300px ; text-align: center"></el-input>
        </el-form-item>
        <!--<el-form-item label="手机号" :label-width="formLabelWidth">-->
        <!--<el-input v-model="insertform.user_phone" autocomplete="off"></el-input>-->
        <!--</el-form-item>-->
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="insertVisible = false">取 消</el-button >
        <el-button type="primary" @click="insertuser">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
  import api from '../../API/api'
  export default {
    name: "login",
    data(){
      return{
        formInline: {},       //登陆时储存的信息
        insertform:{},        //注册用户本地储存
        insertVisible: false, //注册窗口默认隐藏
        formLabelWidth: '80px',   //弹出框的大小
        //控制不为空
        ruleInline: {
          account: [
            { required: true, message: '用户名不可以为空', trigger: 'blur' }
          ],
          password: [
            { required: true, message: '密码不可以为空', trigger: 'blur' },
            { type: 'string', min: 1, message: '密码长度至少大于一位', trigger: 'blur' }
          ]
        }
      }
    },
    methods:{
      //提交登录信息
      handleSubmit() {
        console.log('表单提交，this.formInline=>',this.formInline);
        // this.$Loading.start();       //设置进度条开始数据加载
        // this.$Loading.finish();      //数据加载完成
        // this.$Loading.error();       //数据加载错误
        this.$Spin.show();            //显示进场动画
        setTimeout(() => {
          this.$Spin.hide();
        }, 2000);
         this.$http.post(api.apiConfig.user.login,this.formInline).then(
        res => {
          if (res.data.errno === 0) {
            window.localStorage["token"] = res.data.data.token;
            console.log('登陆成功并且成功获取token',window.localStorage["token"])
            window.localStorage["useraccount"] = res.data.data.view.account;
            setTimeout(() => {
              this.$router.push({
                name: 'mainpage',
                // params: {useraccount: logininfo.account}    //路由传参,对name属性有效果，path不可以带参数
                //let oid =this.$route.params.orderNum;        //接受路由传参
              });
              this.$Message.success('登陆成功');
            }, 2200);
          } else {
            setTimeout(() => {
              this.$Message.warning('登录失败，用户名或者密码错误！');
            }, 2200);
          }
        },
        err => {
          this.$Loading.error();
          this.$message.error("服务器错误！")
        })
        // this.$refs[name].validate((valid) => {
        //   if (valid) {
        //     this.$Message.success('登录成功!');
        //   } else {
        //     this.$Message.error('登录失败!');
        //   }
        // })
      },
      //申请添加用户
      insertWindowopen: function () {
        this.insertVisible = true;
      },
      //提交用户信息
      insertuser:function(){
        let data = {
          account                : this.insertform.account,
          password               : this.insertform.password,
          // password               : this.$md5(this.insertform.password+""),
        };
        console.log(data,'添加用户数据');
        this.$http.post(api.apiConfig.user.adduser,data).then(
          res=>{
            console.log(res.data);
            if(res.data.errno===0){
              this.insertVisible = false;  //关闭弹窗
              this.insertform.account = "";//数据置空
              this.insertform.password = ""; //数据置空
              this.$Message.success('注册用户成功');
            }else if(res.data.errno===300){
              this.insertVisible = false;  //关闭弹窗
              this.$Message.warning('账号已经存在！');
            }else if(res.data.errno===505){
              this.insertVisible = false;  //关闭弹窗
              this.$Message.warning('缺少参数，账号或密码非法');
            }
          },
          err=>{
            console.log("服务器错误！");
          })
      },
    }//methods结束
  } //export结束
</script>

<style scoped>
  .box {
    width: 100%;
    height: 100vh;
    margin: 0px;
    text-align: center;
    background-size: cover;
    background-image:url('../../assets/金色流沙.png');
    background-repeat:no-repeat;
    background-position:center;
    background-attachment:fixed;
  }

  .loginwindow {
    width: 100%;
    text-align: center;
    padding-top: 200px;
  }

</style>



